// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.InventoryBalance) predicate.InventoryBalance {
	return predicate.InventoryBalance(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.InventoryBalance) predicate.InventoryBalance {
	return predicate.InventoryBalance(sql.NotPredicates(p))
}
